const protectedHandLabs = new Set([38, 39, 40, 41, 42, 43, 44, 45, 60]);

for (const spec of specs) {
  if (protectedHandLabs.has(spec.id)) {
    console.log(`skip protected hand-refined 初中物理实验${spec.id}.html :: ${spec.title}`);
    continue;
  }
  const file = path.join(ROOT, `初中物理实验${spec.id}.html`);
  fs.writeFileSync(file, page(spec), "utf8");
  console.log(`wrote ${path.basename(file)} :: ${spec.title}`);
}
